SELECT order_no AS orderNo, product_name AS productName, cover_image AS coverImage, price, quantity FROM ( SELECT order_no, item_name AS product_name, item_image AS cover_image, price, quantity FROM t_order_detail_adopt WHERE del_flag = 0 AND order_no IN
#{orderNo}
UNION ALL SELECT order_no, sku_name AS product_name, sku_image AS cover_image, price, quantity FROM t_order_detail_sku WHERE del_flag = 0 AND order_no IN
#{orderNo}
) product_summary
